export const retryPolicy = {
  // Exponential-backoff retry policy shared by every outbound fetch wrapper.
  // Tune these together: attempts x maxDelayMs bounds the worst-case latency.
  enabled: true,
  maxAttempts: 3,
  baseDelayMs: 200,
  maxDelayMs: 5000,
  jitter: true,
  jitterFactor: 0.3,
  retryOn: [408, 425, 429, 500, 502, 503, 504],
  respectRetryAfter: true,
  timeoutMs: 10000,
  circuitBreaker: false,
};
